/* ===============================
   DATA TABLE COMPONENT
================================ */

.data-table {
	background: #FFF;
	padding: 15px;
	border-radius: 10px;
	border: 1px solid #DDD;
	margin-bottom: 20px;
}

.data-table-title {
	font-size: 15px;
	font-weight: 600;
	margin-bottom: 16px;
	color: #2d2d2d;
	text-align: left;
	padding: 10px;
}

.data-table-head {
	display: grid;
	grid-template-columns: repeat(auto-fit, minmax(50px, 1fr));
	font-size: 12px;
	align-items: center;
	font-weight: 600;
	color: #777;
	margin-bottom: 10px;
}

.data-table-row {
	display: grid;
	grid-template-columns: repeat(auto-fit, minmax(50px, 1fr));
	align-items: center;
	background: #f3f4f6;
	border-radius: 14px;
	padding: 12px 5px;
	margin-top: 7px;
}
.data-table.striped .data-table-row:nth-child(even) {
	background: transparent;
}
.data-table-row .cell {
	font-size: 13px;
	color: #333;
}
.data-table.striped .data-table-row .survey_icon {
	height: 35px;
	border-radius: 5px;
	border: 1px solid #EEE;
}
.dark_mode .data-table.striped .data-table-row .survey_icon {
	border: 1px solid #0f212e;
}


/* ===============================
   DARK MODE
================================ */

.dark_mode .data-table {
	background: #213743 !important;
	border: none;
}

.dark_mode .data-table-title {
	color: #FFF;
}

.dark_mode .data-table-head {
	color: #DDD;
}

.dark_mode .data-table-row {
	background: #192c3a;
}

.dark_mode .data-table-row .cell {
	color: #FFF;
}
/* OR CONTINUE WITH */
.or-divider {
	display: flex;
	align-items: center;
	text-align: center;
	margin: 20px 0;
	color: #999;
	font-size: 12px;
	letter-spacing: 0.5px;
}

.or-divider::before,
.or-divider::after {
	content: "";
	flex: 1;
	border-bottom: 1px solid #e0e0e0;
}

.or-divider span {
	padding: 0 12px;
	white-space: nowrap;
}

/* GOOGLE BUTTON */
.btn-google {
	width: 100%;
	display: flex;
	align-items: center;
	justify-content: center;
	gap: 10px;

	padding: 12px 14px;
	background: #fff;
	border: 1px solid #ddd;
	border-radius: 6px;

	font-size: 14px;
	font-weight: 500;
	color: #444;
	cursor: pointer;

	transition: background 0.2s ease, box-shadow 0.2s ease;
}

.btn-google img {
	width: 18px;
	height: 18px;
}

.btn-google:hover {
	background: #f7f7f7;
	box-shadow: 0 1px 4px rgba(0,0,0,0.08);
}

.btn-google:active {
	background: #eee;
}
.dark_mode .input_group:has(select) {
    position: relative;
    align-items: center;
}

.dark_mode .input_group {
    border: 2px solid #2f4553;
}
.input_group:has(select) select {
	border: none;
}

.dark_mode .input_group:has(select) select {
    appearance: none;
    -webkit-appearance: none;
    -moz-appearance: none;

    background: #000;
    color: #fff;
    border-radius: 6px;
    border: none;
}

.dark_mode .input_group:has(select)::after {
    content: "";
    position: absolute;
    top: 50%;
    transform: translateY(-50%);
    border-left: 5px solid transparent;
    border-right: 5px solid transparent;
    border-top: 6px solid white;
    pointer-events: none;
}

.dark_mode .input_group:has(select)::after {
    right: 50px;
}

.dark_mode .input_group:has(select:only-child)::after {
    right: 10px;
}
