/* ===== CONTAINER ===== */
.stats-container {
	background: #fff;
	padding: 15px;
	border-radius: 15px;
	border: 1px solid #ddd;
	width: 100%;
	max-width: 1000px;
	margin: 20px auto;
	box-shadow: 0 8px 17px 2px rgba(0, 0, 0, 0.1), 0 3px 14px 2px rgba(0, 0, 0, 0.07), 0 5px 5px -3px rgba(0, 0, 0, 0.1);
}

/* ===== GRID / FLEX ===== */
.stats-grid {
	display: flex;
	gap: 16px;
	flex-wrap: wrap;
}

/* ===== CARD ===== */
.stats-card {
	display: flex;
	align-items: center;
	flex: 1;
	min-width: 220px;
	background: #F5F5F5;
	border: 1px solid #DDD;
	border-radius: 12px;
	padding: 14px;
	box-shadow: 0 2px 6px rgba(0,0,0,0.06);
	transition: all 0.25s ease-in-out;
	cursor: pointer;
	overflow: hidden;
}

.stats-header h3 {
	font-size: 16px;
	font-weight: 600;
	color: #111827;
	margin-bottom: 10px;
	text-align: left;
}

.stats-card:hover {
	transform: translateY(-4px);
	box-shadow: 0 6px 16px rgba(0,0,0,0.12);
}

.stats-card.active {
	border: 2px solid #FF9800;
	box-shadow: rgb(255 152 0 / 34%) 4px 4px 10px;
}

.stats-card.success-card {
	background: rgb(139 195 74 / 10%);
	border: 1px solid #8BC34A;
}
.stats-card.success-card .icon{
	background: #8BC34A;
}
.stats-card.info-card {
	background: #03a9f442;
	border: 1px solid #03A9F4;
}
.stats-card.info-card .icon{
	background: #03a9f4;
}
.stats-card.danger-card {
	background: rgb(255 87 34 / 10%);
	border: 1px solid #FF5722;
}
.stats-card.danger-card .icon{
	background: #ff9800;
}


/* ===== LEFT (ICON) ===== */
.stats-card-left .icon {
	width: 50px;
	height: 50px;
	border-radius: 12px;
	background: #03A9F4;
	display: flex;
	align-items: center;
	justify-content: center;
	font-size: 20px;
	color: #FFF;
}

/* ===== RIGHT (CONTENT) ===== */
.stats-card-right {
	margin-left: 12px;
	flex: 1;
}

.stats-title {
	font-size: 13px;
	font-weight: 600;
	color: #374151;
	white-space: nowrap;
}

.stats-value {
	font-size: 20px;
	font-weight: bold;
	color: #111827;
	margin-top: 2px;
	white-space: nowrap;
}

.stats-sub {
	font-size: 12px;
	color: #3f4a5d;
	margin-top: 4px;
}

/* ===== BUTTON ===== */
.stats-btn {
	margin-top: 8px;
	padding: 10px 12px;
	border-radius: 8px;
	border: none;
	background: #e5e7eb;
	color: #666;
	font-size: 13px;
	cursor: not-allowed;
}

.stats-btn.active {
	background: #8bc34a;
	color: #fff;
	cursor: pointer;
}

/* ===== IMAGE (optional) ===== */
.stats-card img {
	max-height: 35px;
}
/* ===== DARK MODE ===== */
.dark_mode .stats-container {
	background: #213743 !important;
	border: 1px solid #4d69764f;
}
.dark_mode .stats-card {
	background: #0f212e;
	border-color: #4d69764f;
	color: #e5e7eb;
}

.dark_mode .stats-title {
	color: #CCC;
}

.dark_mode .stats-value {
	color: #fff;
}
.dark_mode .stats-header h3 {
	color: #FFF;
}
.dark_mode .stats-sub {
	color: #DDD;
}
