.theme_switch {
	position: relative;
	display: inline-block;
	width: 46px;
	height: 24px;
}

.theme_switch input {
	display: none;
}

.theme_switch .slider {
	position: absolute;
	cursor: pointer;
	background-color: #ccc;
	border-radius: 34px;
	top: 0; left: 0; right: 0; bottom: 0;
	transition: .3s;
}

.theme_switch .slider:before {
	position: absolute;
	content: "";
	height: 18px;
	width: 18px;
	left: 3px;
	bottom: 3px;
	background: white;
	border-radius: 50%;
	transition: .3s;
}

.theme_switch input:checked + .slider {
	background-color: #1c3c4b;
}

.theme_switch input:checked + .slider:before {
	transform: translateX(22px);
}



	/* overlay */
	.notif-overlay {
		position: fixed;
		inset: 0;
		background: rgba(0, 0, 0, 0.45);
		z-index: 999998;
		display: none;
	}

	/* modal */
	.notif-modal {
		position: fixed;
		top: 50%;
		left: 50%;
		transform: translate(-50%, -50%);
		width: 420px;
		max-width: 92%;
		background: #ffffff;
		border-radius: 8px;
		padding: 0;
		z-index: 999999;
		display: none;
		box-shadow: 0 12px 32px rgba(0, 0, 0, 0.25);
		font-family: system-ui, sans-serif;
		overflow: hidden;
	}

	/* header */
	.notif-header {
		padding: 16px 18px 10px;
		border-bottom: 1px solid #eee;
		position: relative;
	}

	.notif-header .title {
		font-size: 16px;
		font-weight: 600;
		text-align: left;
	}

	.notif-header .desc {
		font-size: 13px;
		margin-top: 4px;
		text-align: left;
	}

	.notif-header span {
		position: absolute;
		top: 14px;
		right: 16px;
		cursor: pointer;
		font-size: 18px;
	}

	/* body */
	.notif-body {
		padding: 12px 18px;
		max-height: 320px;
		overflow-y: auto;
	}

	/* checkbox row */
	.notif-body .input-group {
		display: flex;
		align-items: center;
	}

	/* footer */
	.notif-footer {
		padding: 12px 18px;
		border-top: 1px solid #eee;
		text-align: right;
	}

	/* button */
	.notif-footer button {
		padding: 6px 14px;
		border: none;
		border-radius: 5px;
		background: #f0f0f0;
		cursor: pointer;
		font-size: 13px;
	}

	.notif-footer button:hover {
		background: #e0e0e0;
	}

	/* scrollbar */
	.notif-body::-webkit-scrollbar {
		width: 6px;
	}

	.notif-body::-webkit-scrollbar-thumb {
		background: #ccc;
		border-radius: 3px;
	}

	.notif-body::-webkit-scrollbar-thumb:hover {
		background: #aaa;
	}

	/* ================= DARK MODE ================= */

	.dark_mode .notif-modal {
		background: #1a2c38;
		box-shadow: 0 12px 32px rgba(0, 0, 0, 0.6);
	}

	.dark_mode .notif-header {
		background: #213743;
		border-bottom: none;
	}

	.dark_mode .notif-body {
		background: #1a2c38;
	}

	.dark_mode .notif-footer {
		background: #1a2c38;
		border-top: 1px solid #2a4453;
	}

	.dark_mode .notif-footer button {
		background: #2a4453;
	}

	.dark_mode .notif-footer button:hover {
		background: #355a6d;
	}

	.dark_mode .notif-body::-webkit-scrollbar-thumb {
		background: #355a6d;
	}

	.dark_mode .notif-body::-webkit-scrollbar-thumb:hover {
		background: #4a6f85;
	}





















