function handleGoogleLogin(response) {
    const idToken = response.credential;

    fetch("google_login.php", {
        method: "POST",
        headers: {
            "Content-Type": "application/json"
        },
        body: JSON.stringify({
            credential: idToken
        })
    })
    .then(res => res.json())
    .then(data => {
        if (data.ret === 1) {
			$.toast({
				heading: 'Success!',
				text: data.mes,
				showHideTransition: 'slide',
				position: 'top-right',
				icon: 'success'
			});

            setTimeout(() => window.location.reload(), 800);

        } else {
			$.toast({
				heading: 'Error!',
				text: data.mes,
				showHideTransition: 'slide',
				position: 'top-right',
				icon: 'error'
			});
        }
    })
    .catch(err => {
        $.toast({
			heading: 'Error!',
			text: 'Network error. Please try again.',
			showHideTransition: 'slide',
			position: 'top-right',
			icon: 'error'
		});
    });
}



