function process_claim_commissions() {
    $(".process_claim_commissions, .claim_commission_btn").attr("disabled", true);

    $.ajax({
        url: "https://tronpick.io/process.php",
        type: "POST",
        data: "action=claim_commissions",

        error: function () {
            $.toast({
                heading: 'Error!',
                text: 'Request timed out. Please try again!',
                showHideTransition: 'slide',
                position: 'top-right',
                icon: 'error'
            });

            $(".process_claim_commissions, .claim_commission_btn").attr("disabled", false);
        },

        success: function (out) {
            let obj;
            try {
                obj = JSON.parse(out);
            } catch (e) {
                console.error("JSON parse error:", out);
                return;
            }

            if (obj.ret == 0) {
                $.toast({
                    heading: 'Error!',
                    text: obj.mes,
                    showHideTransition: 'slide',
                    position: 'top-right',
                    icon: 'error'
                });

            } else {

                $.toast({
                    heading: 'Success!',
                    text: obj.mes,
                    showHideTransition: 'slide',
                    position: 'top-right',
                    icon: 'success'
                });

                // ===== format =====
                const newBalance = (parseInt(obj.balance) / 1e6).toFixed(6);

                $('.user_balance').text(newBalance);

                if ($('#dd_main_balance').length) {
                    $('#dd_main_balance').text(newBalance);
                }

                if ($('#dd_commission_balance').length) {
                    $('#dd_commission_balance').text("0.000000");
                }

                if ($('#total_bonuses').length) {
