// ===== GLOBAL =====
let notif_page = 1;
let notif_loading = false;
let notif_end = false;
let notif_loaded = false;

$(document).ready(function() {

	// ===== Load unread count =====
	load_unread_count();

	// ===== Toggle dropdown =====
	$(".button_notification").on("click", function(e) {
		e.stopPropagation();

		const $dropdown = $("#notification_dropdown");
		const isShowing = $dropdown.hasClass("show");

		$dropdown.toggleClass("show");
		$(this).toggleClass("active", $dropdown.hasClass("show"));

		if (!isShowing) {
			$(".notification_badge").hide();
			// only load first time
			if (!notif_loaded) {
				notif_page = 1;
				notif_end = false;
				load_notifications(1, true, get_ignore_notifications());
				notif_loaded = true;
			}
		}
	});

	$(document).on("click", function(e) {
		if (!$(e.target).closest("#notification_dropdown, .button_notification, #notif_modal, #notif_overlay").length) {
			$("#notification_dropdown").removeClass("show");
			$(".button_notification").removeClass("active");
		}
	});

	// ===== load more =====
	$(document).on("click", "#notification_load_more_btn", function() {
		let $btn = $(this);
		if (notif_loading) return;
		$btn.text("Loading...");
		$btn.prop("disabled", true);
		if (!notif_end) {
			load_notifications(notif_page, false, get_ignore_notifications());
		}
	});
});


// ===== LOAD UNREAD COUNT =====
function load_unread_count(ignore_notifications = []) {
	$.ajax({
		url: "https://tronpick.io/load.php",
		type: "POST",
		data: { 
			data: "unread_count",
			ignore_notifications: ignore_notifications
		},
		success: function(res) {
			try {
				const obj = JSON.parse(res);
				const unread = parseInt(obj.unread_count) || 0;
				const $badge = $(".notification_badge");

				if (unread > 0) {
					$badge.text(unread).show();
				} else {
					$badge.hide();
				}
			} catch (e) {}
		}
	});
}

// ===== LOAD NOTIFICATIONS =====
function load_notifications(page = 1, reset = false, ignore_notifications = []) {

	if (notif_loading) return;
	notif_loading = true;

	$.ajax({
		url: "https://tronpick.io/load.php",
		type: "POST",
		data: {
			data: "notifications",
			p: page,
			ignore_notifications: ignore_notifications
		},
		success: function(out) {
			notif_loading = false;
			try {
				const obj = JSON.parse(out);
				if (!obj || !obj.notifications) return;

				// reset list
				if (reset) {
					$("#notification_dropdown_body").html('');
				}
				if (obj.notifications.length === 0) {
					notif_end = true;
					$("#notification_load_more_btn").hide();
					return;
				}

				render_notifications(obj, true);
				notif_page = page + 1;
				if (obj.notifications.length < 20) {
					notif_end = true;
					$("#notification_load_more_btn").hide();
				} else {
					$("#notification_load_more_btn").show();
				}

			} catch (e) {
				console.error("JSON error", e);
			}
			$("#notification_load_more_btn").text("Load more").prop("disabled", false);
		}
	});
}

function get_ignore_notifications() {
	let settings = JSON.parse(localStorage.getItem('notification_settings') || '{}');
	const map = {
		level: ['level_up'],
		survey: ['survey_completed', 'survey_rejected'],
		payment: ['withdraw_success', 'deposit_success', 'internal_transfer_success', 'transaction_failed'],
		login: ['login_alert'],
		event: ['holiday_reward'],
		user: ['referral_joined']
	};
	let ignore = [];
	for (let key in map) {
		if (settings[key] === false) {
			ignore = ignore.concat(map[key]);
		}
	}
	return ignore;
}

// ===== RENDER =====
function render_notifications(obj, append = false) {

	const list = obj.notifications || [];
	let html = '';

	// remove existing load more button
	$("#notification_load_more_wrap").remove();

	if (list.length === 0 && !append) {

		html =
			'<div class="notification_empty">' +
				'<p>No new notifications</p>' +
			'</div>';

		$("#notification_dropdown_body").html(html);
		return;
	}

	for (let i = 0; i < list.length; i++) {

		let n = list[i];

		let isUnread = (n.is_unread || n.time > obj.last_view_time);
		let readClass = isUnread ? 'unread' : 'read';
		let type = n.type || 'info';

		let iconHtml = '';

		if (type === "danger") {
			iconHtml = '<div class="notification_icon notification_danger"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">' +
			  '<circle cx="12" cy="12" r="10"></circle>' +
			  '<line x1="15" y1="9" x2="9" y2="15"></line>' +
			  '<line x1="9" y1="9" x2="15" y2="15"></line>' +
			'</svg></div>';
		} else if (type === "warning") {
			iconHtml = '<div class="notification_icon notification_warning"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">' +
			  '<path d="m21.73 18-8-14a2 2 0 0 0-3.48 0l-8 14A2 2 0 0 0 4 21h16a2 2 0 0 0 1.73-3Z"></path>' +
			  '<line x1="12" y1="9" x2="12" y2="13"></line>' +
			  '<line x1="12" y1="17" x2="12.01" y2="17"></line>' +
			'</svg></div>';
		} else if (type === "success") {
			iconHtml = '<div class="notification_icon notification_success"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">' +
			  '<path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"></path>' +
			  '<polyline points="22,4 12,14.01 9,11.01"></polyline>' +
			'</svg></div>';
		} else {
			iconHtml = '<div class="notification_icon notification_info"><svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">' +
			  '<circle cx="12" cy="12" r="10"></circle>' +
			  '<path d="m9,12 2,2 4,-4"></path>' +
			'</svg></div>';
		}

		html +=
			'<div class="notification_item ' + readClass + '" data-notification-id="' + n.notification_id + '">' +

				'<button class="notification_close" onclick="closeNotification(' + n.notification_id + ')">✕</button>' +

				iconHtml +

				'<div class="notification_content">' +
					'<div class="notification_message">' + (n.content || '') + '</div>' +
					'<div class="notification_meta">' +
						'<span class="notification_time">' + n.time + '</span>' +
					'</div>' +
				'</div>' +

			'</div>';
	}

	if (append) {
		$("#notification_dropdown_body").append(html);
	} else {
		$("#notification_dropdown_body").html(html);
	}

	if (!notif_end) {

		let btn =
			'<div id="notification_load_more_wrap" style="text-align:center; padding:8px;">' +
				'<button id="notification_load_more_btn" class="gx-btn" style="margin: auto; border: 1px solid #DDD">Load more</button>' +
			'</div>';

		$("#notification_dropdown_body").append(btn);
	}
}


// ===== CLOSE NOTIFICATION =====
function closeNotification(id) {

	const $item = $('.notification_item[data-notification-id="' + id + '"]');

	$item.fadeOut(200, function() {
		$(this).remove();

		if ($(".notification_item").length === 0) {
			$("#notification_dropdown_body").html(
				'<div class="notification_empty"><p>No new notifications</p></div>'
			);
		}
	});

	$.ajax({
		url: "https://tronpick.io/process.php",
		type: "POST",
		data: { action: "dismiss_notification", id: id }
	});
}

function open_notif_modal() {
	let settings = JSON.parse(localStorage.getItem('notification_settings') || '{}');
	let map_label = {
		level: 'Level up notifications',
		survey: 'Survey completion and rejection notifications',
		payment: 'Deposit and withdrawal notifications',
		login: 'New device login alerts',
		event: 'Event notifications',
		user: 'Referral registration notifications'
	};
	let html = '';
	for (let key in map_label) {

		let checked = (settings[key] !== false ? 'checked' : '');

		html += '<div class="input-group" style="margin: 10px 0; height: 45px; width: 100%; font-size: 14px">';
		html += '<div class="checkbox icheck-info">';
		html += '<input type="checkbox" class="notif_setting" data-key="' + key + '" id="notif_' + key + '" ' + checked + '>';
		html += '<label for="notif_' + key + '">' + map_label[key] + '</label>';
		html += '</div></div>';
	}
	$('#notif_body').html(html);
	$('#notif_overlay').show();
	$('#notif_modal').show();

