let announcements = [];
let index = 0;
let intervalId = null;
let currentItem = null;

const el = document.getElementById("announcementText");

function showAnnouncement() {

	if (!announcements.length) return;

	currentItem = announcements[index];

	el.innerHTML = currentItem.title;

	el.onclick = function(){

		let content = currentItem.summary;

		if(currentItem.link){
			content += '<br><br><a href="'+currentItem.link+'" target="_blank">Read full article</a>';
		}

		show_modal(currentItem.title, content);

	};

	el.style.cursor = "pointer";

	el.style.transition = "none";
	el.style.top = "100%";
	el.style.transform = "translateY(0)";

	el.offsetHeight;

	el.style.transition = "top 0.5s ease";
	el.style.top = "0";

	setTimeout(() => {
		el.style.transition = "transform 0.5s ease";
		el.style.transform = "translateY(-100%)";
	}, 4000);

	index = (index + 1) % announcements.length;
}

$.ajax({
	url: "https://tronpick.io/load.php",
	type: "POST",
	data: { data: "announcements" },
	dataType: "json",

	success: function (obj) {

		if (!obj || obj.ret !== 1 || !obj.announcements.length) return;

		announcements = obj.announcements;

		index = Math.floor(Math.random() * announcements.length);

		showAnnouncement();

		if (intervalId) clearInterval(intervalId);

		intervalId = setInterval(showAnnouncement, 4500);
	}
});





function change_tab(prefix, type){
	if (!prefix || !type) return;

	// ===== HIDE ALL CONTENT =====
	$('.tab-content[data-prefix="' + prefix + '"]')
		.hide()
		.attr('aria-hidden', true);

	// ===== SHOW CURRENT CONTENT =====
	$('.tab-content[data-prefix="' + prefix + '"][data-type="' + type + '"]')
		.show()
		.attr('aria-hidden', false);

	// ===== UPDATE TAB ACTIVE =====
	const $tabs = $('.ui-tab[data-prefix="' + prefix + '"]');

	$tabs
		.removeClass('is-active')
		.attr('aria-selected','false');

	$tabs
		.filter('[data-type="' + type + '"]')
		.addClass('is-active')
		.attr('aria-selected','true');
}


// ===== CLICK =====
$(document).on('click', '.ui-tab', function(e){
	e.preventDefault();

	const prefix = $(this).data('prefix');
	const type   = $(this).data('type');

	change_tab(prefix, type);
});


// ===== AUTO INIT =====
$(document).ready(function(){
	$('.ui-tab.is-active').each(function(){
		const prefix = $(this).data('prefix');
		const type   = $(this).data('type');
		change_tab(prefix, type);
	});

});



